}

#xframe .segment[data-layout="stamp-show-wide"] .layout-container:has(> .stamp-show-wide-qr) {
  width: 100%;
  padding: 0.1rem 0.75rem;
  align-items: center !important;
  flex: 0 0 7.25rem !important;
  min-height: 7.25rem;
}

#xframe .segment[data-layout="stamp-show-wide"] .stamp-show-wide-venue {
