  font-size: 1.25rem;
  letter-spacing: 0.12em;
}

#xframe .segment[data-layout="stamp-show-wide"] > .layout-container > .layout-container:has(> .stamp-show-wide-feature-bourse) {
  width: calc(100% - 2.5rem);
  margin: 0.2rem 1.25rem 0.55rem;
  padding: 2px;
  border: 2px solid var(--navy);
